double objectiveFunction(double x) {
    return -pow(x, 2) + 5 * x;
}

// Define the chromosome (individual) structure
struct Individual {
    double gene; // The gene that represents the solution
    double fitness; // The fitness of the individual, which is the value of the function

    Individual(double gene) : gene(gene), fitness(objectiveFunction(gene)) {}
};

// Function to generate an initial population
std::vector<Individual> generateInitialPopulation(int populationSize, double lowerBound, double upperBound) {
    std::vector<Individual> population;
    for (int i = 0; i < populationSize; ++i) {
        double gene = lowerBound + (upperBound - lowerBound) * static_cast<double>(rand()) / RAND_MAX;
        population.push_back(Individual(gene));
    }
    return population;
}

// Function to evaluate the fitness of a population
void evaluatePopulation(std::vector<Individual>& population) {
    for (auto& individual : population) {
        individual.fitness = objectiveFunction(individual.gene);
    }
}

